// 假设 inputData 是您希望处理的输入数据
let inputData = $input.all();
console.log("Input Data:", inputData); // 打印整个输入，检查其格式和内容

let res = [];
for (const item of inputData) {
    let itemJson = item.json;

    // 打印处理的每个项
    console.log("Processing item:", itemJson);

    // 确保 procedure_type 是一个有效的数组并替换为中文描述
    if (Array.isArray(itemJson.procedure_type) && itemJson.procedure_type.length > 0) {
        itemJson.procedure_type_description = itemJson.procedure_type.map(type => {
            switch (type) {
                case 1:
                    return "加工";
                case 2:
                    return "搬运";
                case 3:
                    return "存储";
                case 4:
                    return "检验";
                default:
                    return "未知类型";
            }
        }).join("，"); // 使用逗号连接多个过程类型描述
    } else {
        itemJson.procedure_type_description = "未知过程类型";
    }

    // 处理 procedure_dataupload 字段并设置中文描述
    if (itemJson.hasOwnProperty('procedure_dataupload')) {
        switch (itemJson.procedure_dataupload) {
            case 1:
                itemJson.procedure_dataupload_description = "无需上传数据";
                break;
            case 2:
                itemJson.procedure_dataupload_description = "需要上传数据";
                break;
            default:
                itemJson.procedure_dataupload_description = "未知状态";
                break;
        }
    } else {
        itemJson.procedure_dataupload_description = "未知状态";
    }

    // 新增处理 procedure_scheduling 字段并设置中文描述
    if (itemJson.hasOwnProperty('procedure_scheduling')) {
        switch (itemJson.procedure_scheduling) {
            case 1:
                itemJson.procedure_scheduling_description = "前加工";
                break;
            case 2:
                itemJson.procedure_scheduling_description = "组装测试";
                break;
            case 3:
                itemJson.procedure_scheduling_description = "成品测试";
                break;
            case 4:
                itemJson.procedure_scheduling_description = "包装";
                break;
            default:
                itemJson.procedure_scheduling_description = "未知阶段";
                break;
        }
    } else {
        itemJson.procedure_scheduling_description = "未知阶段";
    }

        // 处理 checkrule 字段并设置中文描述
    if (itemJson.hasOwnProperty('checkrule')) {
        switch (itemJson.checkrule) {
            case true:
                itemJson.checkrule_description = "是";
                break;
            case false:
                itemJson.checkrule_description = "否";
                break;
            default:
                itemJson.checkrule_description = "未知";
                break;
        }
    } else {
        itemJson.checkrule_description = "未知";
    }

    res.push(itemJson);
}

console.log("Final result:", res); // 打印最终结果

return {
    result: res
};

let items = $input.all();

// 提取机型信息
const model = items.length > 0 ? items[0].json['产品型号'] : '未知型号';

let htmlContent = `
<!DOCTYPE html>
<html>
<head>
  <style>
    body { font-family: Arial, sans-serif; }
    table { width: 100%; border-collapse: collapse; margin-top: 20px; }
    th, td { border: 1px solid black; padding: 8px; text-align: center; }
    th { background-color: #f2f2f2; }
    .header { text-align: left; font-weight: bold; margin-top: 20px; }
    .footer { margin-top: 20px; }
    button { margin: 10px; }
  </style>
</head>
<body>
  <h2 style="text-align: center;">流程图及排拉图</h2>
  <div class="header">
    <p>产品型号: ${model}</p>
  </div>

  <!-- 下载和打印按钮 -->
  <button onclick="downloadPage()">下载页面</button>
  <button onclick="window.print()">打印页面</button>

  <table>
    <tr>
      <th>NO</th>
      <th>工序名称</th>
      <th>加工</th>
      <th>搬运</th>
      <th>存储</th>
      <th>检验</th>
      <th>标准工时</th>
      <th>标准人力</th>
      <th>节时工拍</th>
      <th>文件编号</th>
      <th>是否校验前置所有工序</th>
      <th>版本</th>
    </tr>`;

const categories = {};
const summary = {
  前加工: { direct: 0, maxTime: 0, standardTime: 0 },
  组装测试: { direct: 0, maxTime: 0, standardTime: 0 },
  成品测试: { direct: 0, maxTime: 0, standardTime: 0 },
};
const indirectPersonnel = 1; // 每个制程固定的间接人员数量
const totalIndirect = 2; // 总计间接人员

// 将数据按工序分类进行分组
items.forEach((item) => {
  const category = item.json['工序分类'];
  const standardTime = Number(item.json['标准工时']);
  const manpower = Number(item.json['标准人力']);

  if (summary[category]) {
    summary[category].direct += manpower;
    summary[category].standardTime += standardTime;
    summary[category].maxTime = Math.max(
      summary[category].maxTime,
      standardTime,
    );
  }

  if (!categories[category]) {
    categories[category] = [];
  }
  categories[category].push(item.json);
});

items.forEach((item) => {
  const 工序类型 = item.json['工序类型'];
  htmlContent += `<tr>
        <td>${item.json['NO']}</td>
        <td>${item.json['工序名称']}</td>
        <td>${工序类型.includes('加工') ? '●' : ''}</td>
        <td>${工序类型.includes('搬运') ? '●' : ''}</td>
        <td>${工序类型.includes('存储') ? '●' : ''}</td>
        <td>${工序类型.includes('检验') ? '●' : ''}</td>
        <td>${item.json['标准工时']}</td>
        <td>${item.json['标准人力']}</td>
        <td>${item.json['节时工拍']}</td>
        <td>${item.json['文件编号']}</td>
        <td>${item.json['是否校验前置所有工序']}</td>
        <td>${item.json['版本']}</td>
      </tr>`;
});

// 计算和生成统计摘要
htmlContent += `
  </table>
  <div class="footer">
    <p style="text-align: left; font-weight: bold;">统计摘要</p>
    <table>
      <tr>
        <th>制程</th>
        <th>直接人员配置(人)</th>
        <th>间接人员配置(人)</th>
        <th>总人数</th>
        <th>瓶颈时间(S)</th>
        <th>平衡率</th>
        <th>标准工时(S/Pcs)</th>
        <th>UPPH</th>
      </tr>`;

Object.keys(summary).forEach((category) => {
  const data = summary[category];
  const totalPeople = data.direct + indirectPersonnel;
  const upph = data.maxTime
    ? (3600 / data.maxTime / totalPeople).toFixed(2)
    : 'N/A';
  const balanceRate = data.maxTime
    ? ((data.standardTime / (data.maxTime * totalPeople)) * 100).toFixed(1) +
      '%'
    : 'N/A';

  htmlContent += `<tr>
    <td>${category}</td>
    <td>${data.direct}</td>
    <td>${indirectPersonnel}</td>
    <td>${totalPeople}</td>
    <td>${data.maxTime.toFixed(1)}</td>
    <td>${balanceRate}</td>
    <td>${data.standardTime.toFixed(1)}</td>
    <td>${upph}</td>
  </tr>`;
});

// 计算总计
const totalDirect = Object.values(summary).reduce(
  (sum, cat) => sum + cat.direct,
  0,
);
const totalStandardTime = Object.values(summary).reduce(
  (sum, cat) => sum + cat.standardTime,
  0,
);
const totalMaxTime = Math.max(
  ...Object.values(summary).map((cat) => cat.maxTime),
);
const totalPeople =
  totalDirect + indirectPersonnel * Object.keys(summary).length;
const totalBalanceRate = totalMaxTime
  ? ((totalStandardTime / (totalMaxTime * totalPeople)) * 100).toFixed(1) + '%'
  : 'N/A';

htmlContent += `
  <tr>
    <td>Total</td>
    <td>${totalDirect}</td>
    <td>${indirectPersonnel * Object.keys(summary).length}</td>
    <td>${totalPeople}</td>
    <td>${totalMaxTime.toFixed(1)}</td>
    <td>${totalBalanceRate}</td>
    <td>${totalStandardTime.toFixed(1)}</td>
    <td>N/A</td>
  </tr>
</table>`;

// 使用Set来避免重复
const changesSet = new Set();
let hasValidChanges = false;

// 生成修订内容表格
items.forEach((item) => {
  let reasons = item.json['变更原因'] || [];
  let dates = item.json['变更日期'];

  // 如果变更原因是单个值而不是数组，将其转换为数组以一致性处理
  if (!Array.isArray(reasons)) {
    reasons = [reasons];
  }

  reasons.forEach((reason, index) => {
    if (reason) {
      // 确保变更原因存在且不为null
      const changeString = `${reason}_${dates[index]}`;
      if (!changesSet.has(changeString)) {
        changesSet.add(changeString);
        hasValidChanges = true; // 存在有效的变更
      }
    }
  });
});

// 只有在存在有效变更时才添加修订内容表格
if (hasValidChanges) {
  htmlContent += `
    <p style="text-align: left; font-weight: bold;">修订内容</p>
    <table>
      <tr>
        <th>修订内容</th>
        <th>修订日期</th>
      </tr>`;

  changesSet.forEach((changeEntry) => {
    const [reason, date] = changeEntry.split('_');
    htmlContent += `<tr>
      <td>${reason}</td>
      <td>${date}</td>
    </tr>`;
  });

  htmlContent += `
    </table>`;
}

htmlContent += `
  </div>

  <script>
    function downloadPage() {
      const element = document.createElement('a');
      const htmlContent = document.documentElement.outerHTML;
      const file = new Blob([htmlContent], {type: 'text/html'});
      element.href = URL.createObjectURL(file);
      element.download = "page.html";
      document.body.appendChild(element);
      element.click();
      document.body.removeChild(element);
    }
  </script>
</body>
</html>`;

// 去除多余的换行和空白
htmlContent = htmlContent.replace(/\n/g, '').replace(/\s+/g, ' ');

return [{ json: { htmlContent } }];
